import json
with open('baseline-packages.json') as f: base = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def pkg_map(projects):
    result = {}
    for p in projects:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw['topLevelPackages']:
                key = (name, fw['framework'], pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = pkg_map(base['projects'])
a = pkg_map(after['projects'])

changes = []
unchanged = []
for key in sorted(set(list(b.keys()) + list(a.keys()))):
    proj, fw, pkg = key
    bv = b.get(key, 'N/A')
    av = a.get(key, 'N/A')
    if bv != av:
        changes.append((proj, fw, pkg, bv, av))
    else:
        unchanged.append((proj, fw, pkg, bv))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'{c[0]} ({c[1]}): {c[2]} {c[3]} -> {c[4]}')
else:
    print('None')

print(f'\n=== UNCHANGED: {len(unchanged)} packages ===')
for u in unchanged:
    print(f'{u[0]} ({u[1]}): {u[2]} {u[3]}')
"

